+      'last-write-wins': (a, b) => a.timestamp > b.timestamp ? a : b,
+      'first-write-wins': (a, b) => a.timestamp < b.timestamp ? a : b,
+      'merge': (a, b) => this.mergeValues(a, b),
+      'vector-clock': (a, b) => this.vectorClockResolve(a, b)
