+        use std::error::Error;
+
+        let io_err = IoError::Io(std::io::Error::new(std::io::ErrorKind::Other, "test"));
+        assert!(io_err.source().is_some());
+
+        let parse_err = IoError::ParseError("test".to_string());
+        assert!(parse_err.source().is_none());
+    }
