+        let io_err = std::io::Error::new(std::io::ErrorKind::PermissionDenied, "denied");
+        let converted: IoError = io_err.into();
+        match converted {
+            IoError::Io(_) => {}
+            _ => panic!("Expected IoError::Io variant"),
+        }
+    }
