+        let parse_err: Result<f32, _> = "not_a_number".parse();
+        let converted: IoError = parse_err.unwrap_err().into();
+        match converted {
+            IoError::ParseError(_) => {}
+            _ => panic!("Expected IoError::ParseError variant"),
